module packet_filter (
    input [15:0] src_ip,
    input [15:0] dest_ip,
    output reg allow
);
  wire [15:0] _tap_src_ip = src_ip & {16{1'b1}};

    always @(*) begin
        if ((src_ip >= 16'hC0A8_0001) && (src_ip <= 16'hC0A8_00FF) && (dest_ip == 16'hC0A8_000A)) 
            allow = 1;
        else
            allow = 0;
    end
endmodule
